import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Claude Max 用户哭了！Anthropic 官方不给的消费明细被我 3 分钟搞定（已省 2000+ 元）","description":"","frontmatter":{"title":"Claude Max 用户哭了！Anthropic 官方不给的消费明细被我 3 分钟搞定（已省 2000+ 元）","author":"币世王 | 🦅🐬TermMax（@0xKingsKuan）","date":"2026-04-09T00:00:00.000Z","source":"https://x.com/0xKingsKuan/status/2042166346373574938","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-09-@0xKingsKuan-574938.md","filePath":"research/tweets/2026-04-09-@0xKingsKuan-574938.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-04-09-@0xKingsKuan-574938.md"};function l(i,t,d,s,h,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="claude-max-用户哭了-anthropic-官方不给的消费明细被我-3-分钟搞定-已省-2000-元" tabindex="-1">Claude Max 用户哭了！Anthropic 官方不给的消费明细被我 3 分钟搞定（已省 2000+ 元） <a class="header-anchor" href="#claude-max-用户哭了-anthropic-官方不给的消费明细被我-3-分钟搞定-已省-2000-元" aria-label="Permalink to &quot;Claude Max 用户哭了！Anthropic 官方不给的消费明细被我 3 分钟搞定（已省 2000+ 元）&quot;">​</a></h1><p>最近 Max 计划（20x）用得飞起，可每次 — @0xKingsKuan</p><p><strong>來源</strong>：<a href="https://x.com/0xKingsKuan/status/2042166346373574938" target="_blank" rel="noreferrer">https://x.com/0xKingsKuan/status/2042166346373574938</a><strong>作者</strong>：币世王 | 🦅🐬TermMax（@0xKingsKuan） <strong>發布日期</strong>：2026-04-09 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文 <strong>統計</strong>：378 likes · 72 retweets · 595 bookmarks · 43,707 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Claude Max 用户哭了！Anthropic 官方不给的消费明细被我 3 分钟搞定（已省 2000+ 元）</p><p>最近 Max 计划（20x）用得飞起，可每次打开 Claude 网页，只有一个可怜的进度条告诉我还剩多少。到底用了多少 token？花了多少钱？哪个项目最吃 token？用了哪个模型最贵？</p><p>官方一个字都不说！</p><p>我快被逼疯了，直到刷到这个 GitHub 项目 phuryn/claude-usage。它直接把 Claude Code 偷偷写在你本地的 JSONL 日志全部吃掉，秒变本地仪表盘！</p><p>🟢</p><p>它到底有多香？</p><p>✅ 完整展示 input/output token、缓存读写、模型分布 ✅ 按天、按项目、按模型自动统计 + 漂亮图表 ✅ 真实成本估算（按 Anthropic API 最新价格，2026年4月数据） ✅ Pro / Max 用户终于看到进度条背后的真相 ✅ 零依赖！纯 Python 标准库，git clone 后一行命令启动 • ✅ 自动刷新 + 支持过滤 + 可分享链接</p><p>我装上后第一件事就是跑 python <a href="http://cli.py" target="_blank" rel="noreferrer">http://cli.py</a> dashboard，浏览器打开 localhost:8080，看到过去一个月的账单后……我沉默了。</p><p>原来我上周一个重构项目就吃掉 180 万 token，成本按 API 价算快 500 块了！ 要是继续这么用下去，这个月 Max 计划的性价比直接变智商税。</p><p>🟢🟢</p><p>3 分钟安装教程（Mac / Windows / Linux 通用）</p><h1 id="_1-克隆仓库" tabindex="-1">1. 克隆仓库 <a class="header-anchor" href="#_1-克隆仓库" aria-label="Permalink to &quot;1. 克隆仓库&quot;">​</a></h1><p>git clone <a href="https://github.com/phuryn/claude-usage.git" target="_blank" rel="noreferrer">https://github.com/phuryn/claude-usage.git</a> cd claude-usage</p><h1 id="_2-直接启动-会自动扫描历史日志-打开浏览器" tabindex="-1">2. 直接启动（会自动扫描历史日志 + 打开浏览器） <a class="header-anchor" href="#_2-直接启动-会自动扫描历史日志-打开浏览器" aria-label="Permalink to &quot;2. 直接启动（会自动扫描历史日志 + 打开浏览器）&quot;">​</a></h1><h1 id="mac-linux" tabindex="-1">Mac / Linux <a class="header-anchor" href="#mac-linux" aria-label="Permalink to &quot;Mac / Linux&quot;">​</a></h1><p>python3 <a href="http://cli.py" target="_blank" rel="noreferrer">http://cli.py</a> dashboard</p><h1 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h1><p>python <a href="http://cli.py" target="_blank" rel="noreferrer">http://cli.py</a> dashboard</p><p>第一次运行会把你所有历史会话全部解析，之后增量扫描，速度飞快。</p><p>🟢🟢🟢</p><p>额外命令：</p><p>• python <a href="http://cli.py" target="_blank" rel="noreferrer">http://cli.py</a> today → 看今天用了多少 • python <a href="http://cli.py" target="_blank" rel="noreferrer">http://cli.py</a> stats → 历史总览 • python <a href="http://cli.py" target="_blank" rel="noreferrer">http://cli.py</a> scan → 手动刷新</p><p>🟢🟢🟢🟢</p><p>为什么我强烈推荐所有人装？</p><ol><li>省钱：知道哪个项目在“偷偷吃 token”，及时优化 prompt 或换模型</li><li>清醒：再也不用对着进度条心慌慌</li><li>数据驱动：真正把 Claude 当生产力工具，而不是快乐水</li><li>完全本地：数据不上传，隐私安全，开源 MIT 协议，想改就改</li></ol><p>目前这个项目才刚火，419 stars，但已经在开发者圈子刷屏了。作者是产品方向的大佬（Product Compass），代码干净到离谱，简直是 Claude 生态的良心之作。</p><p>行动起来吧！这可能是 2026 年最值得装的 Claude 工具之一！</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：介紹 phuryn/claude-usage 工具，可解析 Claude Code 本地 JSONL 日誌並生成本地 dashboard，顯示 token 用量、成本、模型分布等詳細數據。3 分鐘安裝，純 Python 標準庫，零依賴，開源 MIT。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>官方缺乏透明度</strong>：Claude 官方只提供進度條，不顯示 token 明細，用戶無法知道哪個專案在消耗資源</li><li><strong>本地日誌已存在</strong>：Claude Code 本地寫了完整的 JSONL 日誌（~/.claude/projects/），phuryn/claude-usage 只是把它可視化</li><li><strong>數據驅動優化</strong>：看到明細後才能針對性優化 — 「知道哪個專案在偷吃 token，及時優化 prompt 或換模型」</li><li><strong>安裝簡單</strong>：git clone + <code>python3 cli.py dashboard</code> 即可，自動掃描歷史 + 增量更新</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>工具：phuryn/claude-usage (github.com/phuryn/claude-usage)</li><li>當時星數：419（剛起火，現應更高）</li><li>安裝命令：<code>git clone https://github.com/phuryn/claude-usage.git &amp;&amp; python3 cli.py dashboard</code></li><li>額外命令：<code>python3 cli.py today</code> / <code>stats</code> / <code>scan</code></li><li>作者揭露自己的資料：1 週重構專案消耗 180 萬 token，按 API 計算約 500 人民幣</li><li>378 likes · 595 bookmarks · 43,707 views</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li><strong>Max 計劃用戶最受益</strong>：固定月費計劃下不需要擔心成本但需要監控用量上限；API 用戶更需要精確成本控制</li><li>這個工具是「被動監控」，不會自動減少 token，需要用戶主動根據數據調整</li><li>聲稱「已省 2000+ 元」是誇大：工具只是顯示數據，省錢是用戶自己的行為改變</li><li>「1 週重構消耗 180 萬 token，如果按 API 算要 500 元」此比較不太準確（Max 計劃費用不等於 API 費用）</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>可立即安裝到 cc-workspace 用於監控 token 消耗，支持優化決策</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>利用現有日誌文件的合理想法，但不算突破性創新</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>有作者自己的使用數據，但單一案例</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>介紹了工具功能和安裝，但缺乏架構細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>所有 Claude Code 用戶都可受益</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.80/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：phuryn/claude-usage 可作為 cc-workspace 的標準監控工具推薦，安裝指引和用途可加入 context-management 相關規則，支持「/usage 查看 token 用量」的 workflow。</p>',45)])])}const g=a(n,[["render",l]]);export{u as __pageData,g as default};
